namespace ModProject
{
    internal enum GameState
    {
        Idle,
        Running,
        Won,
        Lost
    }

    internal sealed class LiveMessage
    {
        public string Type;
        public string Content;
        public string UserId;
        public string UserName;
        public int GiftId;
        public string GiftName;
        public int DiamondCount;
    }

    internal sealed class ThreadSafeQueue<T>
    {
        private readonly object _lock = new object();
        private readonly Queue<T> _queue = new Queue<T>();

        public void Enqueue(T item)
        {
            lock (_lock)
            {
                if (_queue.Count < 200)
                    _queue.Enqueue(item);
            }
        }

        public bool TryDequeue(out T item)
        {
            lock (_lock)
            {
                if (_queue.Count > 0)
                {
                    item = _queue.Dequeue();
                    return true;
                }
                item = default(T);
                return false;
            }
        }

        public int Count
        {
            get { lock (_lock) { return _queue.Count; } }
        }
    }

    internal sealed class EffectCooldown
    {
        private readonly Dictionary<string, int> _cooldowns = new Dictionary<string, int>();
        private int _gameTime;

        public void Update(int gameTime)
        {
            _gameTime = gameTime;
        }

        public bool CanTrigger(string effectKey, int cooldownMs)
        {
            if (!_cooldowns.ContainsKey(effectKey))
                return true;
            int elapsed = _gameTime - _cooldowns[effectKey];
            return elapsed >= cooldownMs || elapsed < 0;
        }

        public void MarkTriggered(string effectKey, int gameTime)
        {
            _cooldowns[effectKey] = gameTime;
        }
    }

    public class Mod : Script
    {
        private GameState _state = GameState.Idle;
        private Vehicle _missionVehicle;
        private int _missionStartTime;
        private const int MissionDurationMs = 600000;
        private Vector3 _destination;
        private bool _destinationSet;

        private ClientWebSocket _webSocket;
        private CancellationTokenSource _wsCts;
        private readonly ThreadSafeQueue<LiveMessage> _messageQueue = new ThreadSafeQueue<LiveMessage>();
        private readonly JavaScriptSerializer _jsonSerializer = new JavaScriptSerializer();

        private readonly EffectCooldown _cooldown = new EffectCooldown();
        private const int DefaultCooldownMs = 5000;
        private const int GlobalCooldownMs = 1000;
        private int _lastGlobalTriggerTime;

        private readonly List<Vehicle> _spawnedPursuerVehicles = new List<Vehicle>();
        private readonly List<Ped> _spawnedPursuerPeds = new List<Ped>();
        private readonly List<Ped> _spawnedEscortPeds = new List<Ped>();
        private readonly List<Vehicle> _spawnedEscortVehicles = new List<Vehicle>();

        private bool _bulletproofTiresActive;
        private int _bulletproofTiresEndTime;

        private bool _speedBoostActive;
        private int _speedBoostEndTime;

        private bool _gripReduced;
        private int _gripReducedEndTime;

        private Blip _detourBlip;
        private bool _detourActive;
        private Vector3 _detourPosition;

        private Blip _destinationBlip;

        private bool _engineStalled;
        private int _engineStallEndTime;

        private readonly Random _rng = new Random();

        private readonly string[] _positiveEffects = new string[]
        {
            "vehicle_repair_25",
            "bulletproof_tires_30s",
            "clear_pursuers",
            "speed_boost_5s",
            "escort_npc"
        };

        private readonly string[] _negativeEffects = new string[]
        {
            "tire_burst",
            "engine_stall",
            "spawn_pursuer",
            "reduce_grip",
            "nearby_explosion",
            "detour_checkpoint"
        };

        public Mod()
        {
            Tick += OnTick;
            Interval = 50;
            _destinationSet = false;
            ConnectWebSocketAsync();
        }

        private async void ConnectWebSocketAsync()
        {
            try
            {
                _wsCts = new CancellationTokenSource();
                _webSocket = new ClientWebSocket();
                await _webSocket.ConnectAsync(new Uri("ws://127.0.0.1:60080"), _wsCts.Token);

                var subMsg = "{\"action\":\"serviceSignalSub\",\"channel\":\"IM_MESSAGE_TRANSPORT\"}";
                var subBytes = Encoding.UTF8.GetBytes(subMsg);
                var subSegment = new ArraySegment<byte>(subBytes);
                await _webSocket.SendAsync(subSegment, WebSocketMessageType.Text, true, _wsCts.Token);

                _ = Task.Run(() => ReceiveLoop(_wsCts.Token));
            }
            catch
            {
                _webSocket = null;
            }
        }

        private async void ReceiveLoop(CancellationToken ct)
        {
            var buffer = new byte[8192];
            var messageBuffer = new StringBuilder();
            try
            {
                while (!ct.IsCancellationRequested && _webSocket != null &&
                       _webSocket.State == WebSocketState.Open)
                {
                    var segment = new ArraySegment<byte>(buffer);
                    var result = await _webSocket.ReceiveAsync(segment, ct);
                    if (result.MessageType == WebSocketMessageType.Close)
                        break;

                    string chunk = Encoding.UTF8.GetString(buffer, 0, result.Count);
                    messageBuffer.Append(chunk);

                    if (result.EndOfMessage)
                    {
                        string raw = messageBuffer.ToString();
                        messageBuffer.Clear();
                        ProcessRawMessage(raw);
                    }
                }
            }
            catch
            {
            }
            finally
            {
                try { _webSocket?.Dispose(); } catch { }
                _webSocket = null;
            }
        }

        private void ProcessRawMessage(string raw)
        {
            try
            {
                var dict = _jsonSerializer.Deserialize<Dictionary<string, object>>(raw);
                if (dict == null) return;

                string msgType = null;
                if (dict.ContainsKey("type"))
                    msgType = dict["type"] as string;
                else if (dict.ContainsKey("Type"))
                    msgType = dict["Type"] as string;

                if (string.IsNullOrEmpty(msgType)) return;

                var msg = new LiveMessage { Type = msgType };

                if (dict.ContainsKey("content"))
                    msg.Content = dict["content"] as string ?? "";
                else if (dict.ContainsKey("Content"))
                    msg.Content = dict["Content"] as string ?? "";

                if (dict.ContainsKey("userId"))
                    msg.UserId = dict["userId"] as string;
                else if (dict.ContainsKey("UserId"))
                    msg.UserId = dict["UserId"] as string;

                if (dict.ContainsKey("userName"))
                    msg.UserName = dict["userName"] as string;
                else if (dict.ContainsKey("UserName"))
                    msg.UserName = dict["UserName"] as string;

                if (dict.ContainsKey("giftId"))
                {
                    object gid = dict["giftId"];
                    if (gid is int) msg.GiftId = (int)gid;
                    else int.TryParse(gid?.ToString(), out msg.GiftId);
                }
                else if (dict.ContainsKey("GiftId"))
                {
                    object gid = dict["GiftId"];
                    if (gid is int) msg.GiftId = (int)gid;
                    else int.TryParse(gid?.ToString(), out msg.GiftId);
                }

                if (dict.ContainsKey("giftName"))
                    msg.GiftName = dict["giftName"] as string;
                else if (dict.ContainsKey("GiftName"))
                    msg.GiftName = dict["GiftName"] as string;

                if (dict.ContainsKey("diamondCount"))
                {
                    object dc = dict["diamondCount"];
                    if (dc is int) msg.DiamondCount = (int)dc;
                    else int.TryParse(dc?.ToString(), out msg.DiamondCount);
                }
                else if (dict.ContainsKey("DiamondCount"))
                {
                    object dc = dict["DiamondCount"];
                    if (dc is int) msg.DiamondCount = (int)dc;
                    else int.TryParse(dc?.ToString(), out msg.DiamondCount);
                }

                _messageQueue.Enqueue(msg);
            }
            catch
            {
            }
        }

        private void OnTick(object sender, EventArgs e)
        {
            int gameTime = Game.GameTime;
            _cooldown.Update(gameTime);

            ProcessMessageQueue();

            switch (_state)
            {
                case GameState.Idle:
                    TickIdle(gameTime);
                    break;
                case GameState.Running:
                    TickRunning(gameTime);
                    break;
                case GameState.Won:
                    TickEnded();
                    break;
                case GameState.Lost:
                    TickEnded();
                    break;
            }

            TickTimedEffects(gameTime);
            CleanupDeadEntities();
        }

        private void ProcessMessageQueue()
        {
            while (_messageQueue.TryDequeue(out LiveMessage msg))
            {
                if (_state != GameState.Running) continue;

                int gameTime = Game.GameTime;
                int elapsedSinceGlobal = gameTime - _lastGlobalTriggerTime;
                if (elapsedSinceGlobal < GlobalCooldownMs && elapsedSinceGlobal >= 0)
                    continue;

                if (msg.Type == "WebcastChatMessage" || msg.Type == "WebcastGiftMessage")
                {
                    string effectKey = DetermineEffect(msg);
                    if (!string.IsNullOrEmpty(effectKey))
                    {
                        if (_cooldown.CanTrigger(effectKey, DefaultCooldownMs))
                        {
                            TriggerEffect(effectKey, gameTime);
                            _cooldown.MarkTriggered(effectKey, gameTime);
                            _lastGlobalTriggerTime = gameTime;
                        }
                    }
                }
            }
        }

        private string DetermineEffect(LiveMessage msg)
        {
            if (msg.Type == "WebcastGiftMessage")
            {
                int r = _rng.Next(_positiveEffects.Length + _negativeEffects.Length);
                if (r < _positiveEffects.Length)
                    return _positiveEffects[r];
                else
                    return _negativeEffects[r - _positiveEffects.Length];
            }

            if (msg.Type == "WebcastChatMessage" && !string.IsNullOrEmpty(msg.Content))
            {
                string content = msg.Content.ToLowerInvariant();
                if (content.Contains("repair") || content.Contains("修复")) return "vehicle_repair_25";
                if (content.Contains("tire") || content.Contains("轮胎")) return "bulletproof_tires_30s";
                if (content.Contains("clear") || content.Contains("清空")) return "clear_pursuers";
                if (content.Contains("boost") || content.Contains("加速")) return "speed_boost_5s";
                if (content.Contains("escort") || content.Contains("护航")) return "escort_npc";
                if (content.Contains("burst") || content.Contains("爆胎")) return "tire_burst";
                if (content.Contains("stall") || content.Contains("熄火")) return "engine_stall";
                if (content.Contains("pursu") || content.Contains("追击")) return "spawn_pursuer";
                if (content.Contains("grip") || content.Contains("抓地")) return "reduce_grip";
                if (content.Contains("explo") || content.Contains("爆炸")) return "nearby_explosion";
                if (content.Contains("detour") || content.Contains("绕路")) return "detour_checkpoint";
            }

            return null;
        }

        private void TriggerEffect(string effectKey, int gameTime)
        {
            if (_missionVehicle == null || !_missionVehicle.Exists() || !_missionVehicle.IsAlive)
                return;

            switch (effectKey)
            {
                case "vehicle_repair_25":
                    RepairVehicle25();
                    UI.Notify("~g~[正面效果] ~w~车辆修复 25%");
                    break;
                case "bulletproof_tires_30s":
                    EnableBulletproofTires(gameTime);
                    UI.Notify("~g~[正面效果] ~w~防爆轮胎 30 秒");
                    break;
                case "clear_pursuers":
                    ClearPursuers();
                    UI.Notify("~g~[正面效果] ~w~追兵已清空");
                    break;
                case "speed_boost_5s":
                    ActivateSpeedBoost(gameTime);
                    UI.Notify("~g~[正面效果] ~w~短暂加速 5 秒");
                    break;
                case "escort_npc":
                    SpawnEscortNpc();
                    UI.Notify("~g~[正面效果] ~w~护航 NPC 已生成");
                    break;
                case "tire_burst":
                    BurstRandomTire();
                    UI.Notify("~r~[负面效果] ~w~爆胎！");
                    break;
                case "engine_stall":
                    StallEngine(gameTime);
                    UI.Notify("~r~[负面效果] ~w~引擎熄火！");
                    break;
                case "spawn_pursuer":
                    SpawnPursuer();
                    UI.Notify("~r~[负面效果] ~w~追击车辆已生成！");
                    break;
                case "reduce_grip":
                    ReduceGrip(gameTime);
                    UI.Notify("~r~[负面效果] ~w~抓地力降低！");
                    break;
                case "nearby_explosion":
                    NearbyExplosion();
                    UI.Notify("~r~[负面效果] ~w~附近爆炸！");
                    break;
                case "detour_checkpoint":
                    SetDetourCheckpoint();
                    UI.Notify("~r~[负面效果] ~w~强制绕路检查点！");
                    break;
            }
        }

        private void TickIdle(int gameTime)
        {
            Ped player = Game.Player.Character;
            if (player == null) return;

            Vehicle currentVehicle = player.CurrentVehicle;
            if (currentVehicle != null && currentVehicle.Exists() && currentVehicle.IsAlive)
            {
                _missionVehicle = currentVehicle;
                _missionStartTime = gameTime;

                Vector3 wp = World.WaypointPosition;
                if (wp != Vector3.Zero && wp.DistanceTo(player.Position) > 10f)
                {
                    _destination = wp;
                }
                else
                {
                    _destination = player.Position + player.ForwardVector * 800f;
                }
                _destinationSet = true;

                if (_destinationBlip != null && _destinationBlip.Exists())
                    _destinationBlip.Delete();
                _destinationBlip = World.CreateBlip(_destination);
                if (_destinationBlip != null)
                {
                    _destinationBlip.Name = "送货终点";
                    _destinationBlip.Color = BlipColor.Yellow;
                    _destinationBlip.ShowRoute = true;
                    _destinationBlip.IsShortRange = false;
                }

                _state = GameState.Running;
                UI.Notify("~y~[任务开始] ~w~在 10 分钟内将货物送达终点！");
            }
        }

        private void TickRunning(int gameTime)
        {
            if (_missionVehicle == null || !_missionVehicle.Exists())
            {
                LoseGame("任务车辆丢失");
                return;
            }

            if (_missionVehicle.IsDead)
            {
                LoseGame("车辆已爆炸");
                return;
            }

            Ped player = Game.Player.Character;
            if (player == null)
            {
                LoseGame("玩家不可用");
                return;
            }

            Vehicle currentVehicle = player.CurrentVehicle;
            if (currentVehicle == null || !currentVehicle.Exists() || currentVehicle != _missionVehicle)
            {
                LoseGame("已更换车辆");
                return;
            }

            int elapsed = gameTime - _missionStartTime;
            if (elapsed >= MissionDurationMs)
            {
                LoseGame("时间耗尽");
                return;
            }

            if (_detourActive && _detourBlip != null && _detourBlip.Exists())
            {
                float distToDetour = _missionVehicle.Position.DistanceTo(_detourPosition);
                if (distToDetour < 15f)
                {
                    _detourBlip.Delete();
                    _detourBlip = null;
                    _detourActive = false;
                    if (_destinationBlip != null && _destinationBlip.Exists())
                        _destinationBlip.ShowRoute = true;
                    UI.Notify("~y~检查点已通过，继续前往终点");
                }
            }

            if (!_detourActive && _destinationSet)
            {
                float distToDest = _missionVehicle.Position.DistanceTo(_destination);
                if (distToDest < 20f)
                {
                    WinGame();
                    return;
                }
            }

            int remaining = MissionDurationMs - elapsed;
            if (remaining % 30000 < 55 && remaining > 0)
            {
            }
        }

        private void TickEnded()
        {
        }

        private void TickTimedEffects(int gameTime)
        {
            if (_bulletproofTiresActive && gameTime > _bulletproofTiresEndTime)
            {
                _bulletproofTiresActive = false;
                if (_missionVehicle != null && _missionVehicle.Exists())
                    _missionVehicle.CanTiresBurst = true;
            }

            if (_speedBoostActive && gameTime > _speedBoostEndTime)
            {
                _speedBoostActive = false;
            }

            if (_gripReduced && gameTime > _gripReducedEndTime)
            {
                _gripReduced = false;
                if (_missionVehicle != null && _missionVehicle.Exists())
                {
                    try
                    {
                        Function.Call((Hash)0x1A8E2C8B9CF45438, _missionVehicle.Handle, false);
                    }
                    catch { }
                }
            }

            if (_engineStalled && gameTime > _engineStallEndTime)
            {
                _engineStalled = false;
                if (_missionVehicle != null && _missionVehicle.Exists())
                {
                    _missionVehicle.EngineHealth = 300f;
                }
            }
        }

        private void WinGame()
        {
            _state = GameState.Won;
            UI.Notify("~g~[胜利] ~w~货物已安全送达！");
            CleanupMission();
        }

        private void LoseGame(string reason)
        {
            _state = GameState.Lost;
            UI.Notify("~r~[失败] ~w~" + reason);
            CleanupMission();
        }

        private void CleanupMission()
        {
            ClearPursuers();

            foreach (var ped in _spawnedEscortPeds)
            {
                try { if (ped != null && ped.Exists()) ped.Delete(); } catch { }
            }
            _spawnedEscortPeds.Clear();

            foreach (var veh in _spawnedEscortVehicles)
            {
                try { if (veh != null && veh.Exists()) veh.Delete(); } catch { }
            }
            _spawnedEscortVehicles.Clear();

            if (_detourBlip != null && _detourBlip.Exists())
            {
                _detourBlip.Delete();
                _detourBlip = null;
            }
            _detourActive = false;

            if (_destinationBlip != null && _destinationBlip.Exists())
            {
                _destinationBlip.Delete();
                _destinationBlip = null;
            }

            _bulletproofTiresActive = false;
            _speedBoostActive = false;
            _gripReduced = false;
            _engineStalled = false;
        }

        private void CleanupDeadEntities()
        {
            for (int i = _spawnedPursuerVehicles.Count - 1; i >= 0; i--)
            {
                var v = _spawnedPursuerVehicles[i];
                if (v == null || !v.Exists() || v.IsDead)
                {
                    try { v?.Delete(); } catch { }
                    _spawnedPursuerVehicles.RemoveAt(i);
                }
            }
            for (int i = _spawnedPursuerPeds.Count - 1; i >= 0; i--)
            {
                var p = _spawnedPursuerPeds[i];
                if (p == null || !p.Exists() || p.IsDead)
                {
                    try { p?.Delete(); } catch { }
                    _spawnedPursuerPeds.RemoveAt(i);
                }
            }
            for (int i = _spawnedEscortPeds.Count - 1; i >= 0; i--)
            {
                var p = _spawnedEscortPeds[i];
                if (p == null || !p.Exists() || p.IsDead)
                {
                    try { p?.Delete(); } catch { }
                    _spawnedEscortPeds.RemoveAt(i);
                }
            }
            for (int i = _spawnedEscortVehicles.Count - 1; i >= 0; i--)
            {
                var v = _spawnedEscortVehicles[i];
                if (v == null || !v.Exists() || v.IsDead)
                {
                    try { v?.Delete(); } catch { }
                    _spawnedEscortVehicles.RemoveAt(i);
                }
            }
        }

        private void RepairVehicle25()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            float currentBody = _missionVehicle.BodyHealth;
            float currentEngine = _missionVehicle.EngineHealth;

            float newBody = Math.Min(currentBody + 250f, 1000f);
            float newEngine = Math.Min(currentEngine + 250f, 1000f);

            _missionVehicle.BodyHealth = newBody;
            _missionVehicle.EngineHealth = newEngine;
            _missionVehicle.Health = Math.Min(_missionVehicle.Health + 250, 1000);
        }

        private void EnableBulletproofTires(int gameTime)
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            _missionVehicle.CanTiresBurst = false;
            _bulletproofTiresActive = true;
            _bulletproofTiresEndTime = gameTime + 30000;
        }

        private void ClearPursuers()
        {
            foreach (var v in _spawnedPursuerVehicles)
            {
                try { if (v != null && v.Exists()) v.Delete(); } catch { }
            }
            _spawnedPursuerVehicles.Clear();

            foreach (var p in _spawnedPursuerPeds)
            {
                try { if (p != null && p.Exists()) p.Delete(); } catch { }
            }
            _spawnedPursuerPeds.Clear();
        }

        private void ActivateSpeedBoost(int gameTime)
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            float currentSpeed = _missionVehicle.Speed;
            _missionVehicle.Speed = currentSpeed * 1.3f;
            _speedBoostActive = true;
            _speedBoostEndTime = gameTime + 5000;
        }

        private void SpawnEscortNpc()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            try
            {
                Vector3 spawnPos = _missionVehicle.Position + _missionVehicle.RightVector * 6f;
                Model pedModel = PedHash.FibOfficeM01;
                pedModel.Request();
                int waitCount = 0;
                while (!pedModel.IsLoaded && waitCount < 50)
                {
                    Script.Yield();
                    waitCount++;
                }
                if (!pedModel.IsLoaded)
                {
                    pedModel.MarkAsNoLongerNeeded();
                    return;
                }

                Ped escortPed = World.CreatePed(pedModel, spawnPos, _missionVehicle.Heading);
                pedModel.MarkAsNoLongerNeeded();

                if (escortPed == null) return;

                escortPed.Weapons.Give(WeaponHash.CarbineRifle, 500, true, true);
                escortPed.RelationshipGroup = Game.Player.Character.RelationshipGroup;
                escortPed.Task.FightAgainstHatedTargets(100f);
                _spawnedEscortPeds.Add(escortPed);

                Model carModel = VehicleHash.Dubsta2;
                carModel.Request();
                waitCount = 0;
                while (!carModel.IsLoaded && waitCount < 50)
                {
                    Script.Yield();
                    waitCount++;
                }
                if (carModel.IsLoaded)
                {
                    Vector3 carSpawn = spawnPos + Vector3.WorldUp * 2f;
                    Vehicle escortCar = World.CreateVehicle(carModel, carSpawn, _missionVehicle.Heading);
                    carModel.MarkAsNoLongerNeeded();
                    if (escortCar != null)
                    {
                        escortCar.MarkAsNoLongerNeeded();
                        _spawnedEscortVehicles.Add(escortCar);
                    }
                }
            }
            catch { }
        }

        private void BurstRandomTire()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            try
            {
                _missionVehicle.CanTiresBurst = true;
                int wheelIndex = _rng.Next(0, 4);
                Function.Call((Hash)0xBFEBAF4E4F0D9F1C, _missionVehicle.Handle, wheelIndex, true, 1000f);
            }
            catch { }
        }

        private void StallEngine(int gameTime)
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            _missionVehicle.EngineHealth = 0f;
            _engineStalled = true;
            _engineStallEndTime = gameTime + 4000;
        }

        private void SpawnPursuer()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            try
            {
                Vector3 spawnPos = _missionVehicle.Position + (_missionVehicle.RightVector * 40f) + (Vector3.WorldUp * 5f);
                Model carModel = VehicleHash.Schafter2;
                carModel.Request();
                int waitCount = 0;
                while (!carModel.IsLoaded && waitCount < 50)
                {
                    Script.Yield();
                    waitCount++;
                }
                if (!carModel.IsLoaded)
                {
                    carModel.MarkAsNoLongerNeeded();
                    return;
                }

                Vehicle pursuerCar = World.CreateVehicle(carModel, spawnPos, _missionVehicle.Heading);
                carModel.MarkAsNoLongerNeeded();
                if (pursuerCar == null) return;

                pursuerCar.MarkAsNoLongerNeeded();
                _spawnedPursuerVehicles.Add(pursuerCar);

                Model pedModel = PedHash.Gunman01SFY;
                pedModel.Request();
                waitCount = 0;
                while (!pedModel.IsLoaded && waitCount < 50)
                {
                    Script.Yield();
                    waitCount++;
                }
                if (!pedModel.IsLoaded)
                {
                    pedModel.MarkAsNoLongerNeeded();
                    return;
                }

                Ped driver = World.CreatePed(pedModel, spawnPos, _missionVehicle.Heading);
                pedModel.MarkAsNoLongerNeeded();
                if (driver == null) return;

                driver.SetIntoVehicle(pursuerCar, VehicleSeat.Driver);
                driver.Weapons.Give(WeaponHash.Pistol, 200, true, true);
                driver.Task.VehicleChase(Game.Player.Character);
                _spawnedPursuerPeds.Add(driver);
            }
            catch { }
        }

        private void ReduceGrip(int gameTime)
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            try
            {
                Function.Call((Hash)0x1A8E2C8B9CF45438, _missionVehicle.Handle, true);
                _gripReduced = true;
                _gripReducedEndTime = gameTime + 8000;
            }
            catch { }
        }

        private void NearbyExplosion()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;

            int healthBefore = _missionVehicle.Health;
            Vector3 explosionPos = _missionVehicle.Position +
                (_missionVehicle.RightVector * (float)(_rng.NextDouble() * 8f + 6f)) +
                (_missionVehicle.ForwardVector * (float)(_rng.NextDouble() * 5f - 2.5f));

            World.AddExplosion(explosionPos, ExplosionType.Default, 6f, 0.5f, null, true, false);

            if (_missionVehicle.Exists() && _missionVehicle.IsAlive && _missionVehicle.Health < 200)
            {
                _missionVehicle.Health = 200;
            }
        }

        private void SetDetourCheckpoint()
        {
            if (_missionVehicle == null || !_missionVehicle.Exists()) return;
            if (_detourActive) return;

            Vector3 forward = _missionVehicle.ForwardVector;
            Vector3 right = _missionVehicle.RightVector;
            float offsetForward = (float)(_rng.NextDouble() * 200f + 150f);
            float offsetRight = (float)(_rng.NextDouble() * 120f - 60f);
            _detourPosition = _missionVehicle.Position + forward * offsetForward + right * offsetRight;

            if (_detourBlip != null && _detourBlip.Exists())
                _detourBlip.Delete();

            _detourBlip = World.CreateBlip(_detourPosition);
            if (_detourBlip != null)
            {
                _detourBlip.Name = "绕路检查点";
                _detourBlip.Color = BlipColor.Red;
                _detourBlip.ShowRoute = true;
                _detourBlip.IsShortRange = false;
                _detourActive = true;
            }

            if (_destinationBlip != null && _destinationBlip.Exists())
                _destinationBlip.ShowRoute = false;
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                try
                {
                    _wsCts?.Cancel();
                    _webSocket?.Dispose();
                }
                catch { }

                CleanupMission();
            }
            base.Dispose(disposing);
        }
    }
